        [self.observerTokens addObject:[[NSNotificationCenter defaultCenter] addObserverForName:WBVipReturnNotification object:nil queue:nil usingBlock:^(NSNotification * _Nonnull notification) {
            dispatch_after(dispatch_time(DISPATCH_TIME_NOW, (int64_t)(POPUP_DELAY * NSEC_PER_SEC)), dispatch_get_main_queue(), ^{
