- (void)handleStoredPopup {
    if (self.storePopupData) {
        @synchronized (self) {
            WBPopupShowStatus status = [[WBPopupDecisionMaker sharedInstance] shouldShowPopup];
            if (status == WBPopupShowStatusShow) {
                [self handleRichMessages:self.storePopupData];  // 展示暂存的弹窗数据
                self.storePopupData = nil;
