}

+ (NSArray<NSDictionary *> *)modelsToDicts:(NSArray<WBRichMessageLinkModel *> *)arrayModel {
	NSMutableArray *arrayDict = [NSMutableArray arrayWithCapacity:arrayModel.count];
	for (WBRichMessageLinkModel *model in arrayModel) {
		NSDictionary *dict = [model convertToDict];
		[arrayDict addObject:dict];
	}
